contracts/FeedConsensus.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";

/**
 * @title FeedConsensus
 * @dev 共识引擎 — Commit-Reveal 两阶段价格提交 — UUPS 可升级
 *
 * 流程：
 * 1. Commit 阶段：喂价员提交 priceHash = keccak256(price, salt)
 * 2. Reveal 阶段：喂价员揭示 price + salt，合约验证哈希
 * 3. 共识计算：去极值中位数（链下计算，链上验证签名）
 * 4. 结算：根据共识价格结算订单
 */
contract FeedConsensus is
    Initializable,
    OwnableUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable
{
    // ============ 数据结构 ============

    /// @notice 订单阶段
    enum OrderPhase { NONE, COMMIT, REVEAL, CONSENSUS, SETTLED, DISPUTED }

    /// @notice 价格提交记录
    struct PriceCommit {
        bytes32 priceHash;    // keccak256(abi.encodePacked(price, salt))
        uint256 revealedPrice; // 揭示后的价格 (8 decimals)
        bool committed;
        bool revealed;
        uint256 commitTime;
    }

    /// @notice 订单信息
    struct OrderInfo {
        bytes32 orderId;
        string symbol;
        uint256 notionalAmount;
        OrderPhase phase;
        uint256 commitDeadline;
        uint256 revealDeadline;
        uint256 consensusPrice;
        uint256 requiredQuorum;
        uint256 commitCount;
        uint256 revealCount;
        address creator;
    }

    // ============ 状态变量 ============

    /// @notice orderId → 订单信息
    mapping(bytes32 => OrderInfo) public orders;

    /// @notice orderId → feeder → 提交记录
    mapping(bytes32 => mapping(address => PriceCommit)) public commits;

    /// @notice orderId → 揭示地址列表
    mapping(bytes32 => address[]) public revealedFeeders;

    /// @notice 授权操作者（FeedEngine 主合约）
    mapping(address => bool) public authorizedOperators;

    /// @notice Commit 阶段时长（秒）
    uint256 public commitWindow;

    /// @notice Reveal 阶段时长（秒）
    uint256 public revealWindow;

    /// @notice 最大偏差阈值（basis points，如 500 = 5%）
    uint256 public maxDeviationBps;

    // ============ 事件 ============

    event OrderCreated(bytes32 indexed orderId, string symbol, uint256 notionalAmount, uint256 quorum);
    event PriceCommitted(bytes32 indexed orderId, address indexed feeder, bytes32 priceHash);
    event PriceRevealed(bytes32 indexed orderId, address indexed feeder, uint256 price);
    event ConsensusReached(bytes32 indexed orderId, uint256 consensusPrice, uint256 participantCount);
    event OrderDisputed(bytes32 indexed orderId, string reason);
    event OperatorUpdated(address indexed operator, bool authorized);

    // ============ Modifiers ============

    modifier onlyOperator() {
        require(authorizedOperators[msg.sender] || msg.sender == owner(), "FeedConsensus: not operator");
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /**
     * @notice 初始化
     * @param owner_ 合约所有者
     * @param commitWindow_ Commit 阶段时长（秒）
     * @param revealWindow_ Reveal 阶段时长（秒）
     */
    function initialize(
        address owner_,
        uint256 commitWindow_,
        uint256 revealWindow_
    ) public initializer {
        __Ownable_init(owner_);
        __UUPSUpgradeable_init();
        __ReentrancyGuard_init();

        commitWindow = commitWindow_;
        revealWindow = revealWindow_;
        maxDeviationBps = 500; // 默认 5%
    }

    // ============ 管理函数 ============

    /**
     * @notice 设置授权操作者
     */
    function setOperator(address operator, bool authorized) external onlyOwner {
        authorizedOperators[operator] = authorized;
        emit OperatorUpdated(operator, authorized);
    }

    /**
     * @notice 更新时间窗口
     */
    function updateWindows(uint256 commitWindow_, uint256 revealWindow_) external onlyOwner {
        require(commitWindow_ >= 60 && revealWindow_ >= 60, "Window too short");
        commitWindow = commitWindow_;
        revealWindow = revealWindow_;
    }

    /**
     * @notice 更新最大偏差阈值
     */
    function updateMaxDeviation(uint256 bps) external onlyOwner {
        require(bps >= 10 && bps <= 5000, "Invalid deviation");
        maxDeviationBps = bps;
    }

    // ============ 核心函数 ============

    /**
     * @notice 创建喂价订单
     * @param orderId 订单唯一标识
     * @param symbol 标的代码
     * @param notionalAmount 名义本金
     * @param quorum 法定人数
     */
    function createOrder(
        bytes32 orderId,
        string calldata symbol,
        uint256 notionalAmount,
        uint256 quorum
    ) external onlyOperator {
        require(orders[orderId].phase == OrderPhase.NONE, "Order exists");
        require(quorum >= 3, "Quorum too low");

        orders[orderId] = OrderInfo({
            orderId: orderId,
            symbol: symbol,
            notionalAmount: notionalAmount,
            phase: OrderPhase.COMMIT,
            commitDeadline: block.timestamp + commitWindow,
            revealDeadline: block.timestamp + commitWindow + revealWindow,
            consensusPrice: 0,
            requiredQuorum: quorum,
            commitCount: 0,
            revealCount: 0,
            creator: msg.sender
        });

        emit OrderCreated(orderId, symbol, notionalAmount, quorum);
    }

    /**
     * @notice 提交价格哈希（Commit 阶段）
     * @param orderId 订单 ID
     * @param priceHash keccak256(abi.encodePacked(price, salt))
     */
    function submitPriceHash(bytes32 orderId, bytes32 priceHash) external {
        OrderInfo storage order = orders[orderId];
        require(order.phase == OrderPhase.COMMIT, "Not in commit phase");
        require(block.timestamp <= order.commitDeadline, "Commit deadline passed");
        require(!commits[orderId][msg.sender].committed, "Already committed");

        commits[orderId][msg.sender] = PriceCommit({
            priceHash: priceHash,
            revealedPrice: 0,
            committed: true,
            revealed: false,
            commitTime: block.timestamp
        });

        order.commitCount++;

        // 达到法定人数后自动切换到 Reveal 阶段
        if (order.commitCount >= order.requiredQuorum) {
            order.phase = OrderPhase.REVEAL;
        }

        emit PriceCommitted(orderId, msg.sender, priceHash);
    }

    /**
     * @notice 批量提交价格哈希
     * @param orderIds 订单 ID 数组
     * @param priceHashes 对应的价格哈希数组
     */
    function batchSubmitPriceHash(
        bytes32[] calldata orderIds,
        bytes32[] calldata priceHashes
    ) external {
        require(orderIds.length == priceHashes.length, "Length mismatch");
        require(orderIds.length <= 20, "Batch too large");

        for (uint256 i = 0; i < orderIds.length; i++) {
            OrderInfo storage order = orders[orderIds[i]];
            if (
                order.phase == OrderPhase.COMMIT &&
                block.timestamp <= order.commitDeadline &&
                !commits[orderIds[i]][msg.sender].committed
            ) {
                commits[orderIds[i]][msg.sender] = PriceCommit({
                    priceHash: priceHashes[i],
                    revealedPrice: 0,
                    committed: true,
                    revealed: false,
                    commitTime: block.timestamp
                });
                order.commitCount++;

                if (order.commitCount >= order.requiredQuorum) {
                    order.phase = OrderPhase.REVEAL;
                }

                emit PriceCommitted(orderIds[i], msg.sender, priceHashes[i]);
            }
        }
    }

    /**
     * @notice 揭示价格（Reveal 阶段）
     * @param orderId 订单 ID
     * @param price 实际价格 (8 decimals)
     * @param salt 随机盐值
     */
    function revealPrice(
        bytes32 orderId,
        uint256 price,
        bytes32 salt
    ) external {
        OrderInfo storage order = orders[orderId];
        require(
            order.phase == OrderPhase.REVEAL ||
            (order.phase == OrderPhase.COMMIT && order.commitCount >= order.requiredQuorum),
            "Not in reveal phase"
        );
        require(block.timestamp <= order.revealDeadline, "Reveal deadline passed");

        PriceCommit storage commit = commits[orderId][msg.sender];
        require(commit.committed, "Not committed");
        require(!commit.revealed, "Already revealed");

        // 核心验证：哈希匹配
        bytes32 computedHash = keccak256(abi.encodePacked(price, salt));
        require(computedHash == commit.priceHash, "Hash mismatch");

        commit.revealedPrice = price;
        commit.revealed = true;
        order.revealCount++;
        revealedFeeders[orderId].push(msg.sender);

        // 确保进入 REVEAL 阶段
        if (order.phase == OrderPhase.COMMIT) {
            order.phase = OrderPhase.REVEAL;
        }

        emit PriceRevealed(orderId, msg.sender, price);
    }

    /**
     * @notice 提交共识价格（由 operator 在链下计算后提交）
     * @param orderId 订单 ID
     * @param consensusPrice 共识价格 (8 decimals)
     */
    function submitConsensus(
        bytes32 orderId,
        uint256 consensusPrice
    ) external onlyOperator {
        OrderInfo storage order = orders[orderId];
        require(order.phase == OrderPhase.REVEAL, "Not in reveal phase");
        require(order.revealCount >= order.requiredQuorum, "Quorum not met");

        order.consensusPrice = consensusPrice;
        order.phase = OrderPhase.CONSENSUS;

        emit ConsensusReached(orderId, consensusPrice, order.revealCount);
    }

    /**
     * @notice 结算订单
     * @param orderId 订单 ID
     */
    function settleOrder(bytes32 orderId) external onlyOperator {
        OrderInfo storage order = orders[orderId];
        require(order.phase == OrderPhase.CONSENSUS, "Not in consensus phase");

        order.phase = OrderPhase.SETTLED;
    }

    /**
     * @notice 标记订单争议
     * @param orderId 订单 ID
     * @param reason 争议原因
     */
    function disputeOrder(bytes32 orderId, string calldata reason) external onlyOperator {
        OrderInfo storage order = orders[orderId];
        require(
            order.phase == OrderPhase.REVEAL || order.phase == OrderPhase.CONSENSUS,
            "Cannot dispute in this phase"
        );

        order.phase = OrderPhase.DISPUTED;
        emit OrderDisputed(orderId, reason);
    }

    // ============ 查询函数 ============

    /**
     * @notice 获取订单状态
     */
    function getOrderPhase(bytes32 orderId) external view returns (OrderPhase) {
        return orders[orderId].phase;
    }

    /**
     * @notice 获取共识价格
     */
    function getConsensusPrice(bytes32 orderId) external view returns (uint256) {
        return orders[orderId].consensusPrice;
    }

    /**
     * @notice 获取订单的揭示喂价员列表
     */
    function getRevealedFeeders(bytes32 orderId) external view returns (address[] memory) {
        return revealedFeeders[orderId];
    }

    /**
     * @notice 获取喂价员对某订单的提交记录
     */
    function getCommit(bytes32 orderId, address feeder)
        external
        view
        returns (bytes32 priceHash, uint256 revealedPrice, bool committed, bool revealed)
    {
        PriceCommit storage c = commits[orderId][feeder];
        return (c.priceHash, c.revealedPrice, c.committed, c.revealed);
    }

    /**
     * @notice 计算价格哈希（辅助函数，前端可用）
     * @param price 价格 (8 decimals)
     * @param salt 随机盐值
     */
    function computePriceHash(uint256 price, bytes32 salt) external pure returns (bytes32) {
        return keccak256(abi.encodePacked(price, salt));
    }

    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
}

contracts/FeedEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import "./FeedConsensus.sol";
import "./RewardPenalty.sol";
import "./FeederLicense.sol";

/**
 * @title FeedEngine
 * @dev 主合约（门面模式） — UUPS 可升级
 *
 * 整合子合约功能：
 * - 喂价员注册 + 等级管理
 * - 订单创建 + 抢单 + 结算
 * - 质押 (stake/unstake/withdraw)
 * - 调用 FeedConsensus 进行共识
 * - 调用 RewardPenalty 进行奖惩
 */
contract FeedEngine is
    Initializable,
    OwnableUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable
{
    // ============ 数据结构 ============

    /// @notice 喂价员等级
    enum FeederRank { F, E, D, C, B, A, S }

    /// @notice 喂价员信息
    struct FeederInfo {
        bool registered;
        FeederRank rank;
        uint256 xp;
        uint256 totalFeeds;
        uint256 stakedAmount;
        uint256 unstakeRequestTime; // 解锁请求时间
        uint256 dailyGrabCount;     // 当日抢单数
        uint256 lastGrabDate;       // 上次抢单日期
    }

    /// @notice 内部订单记录
    struct EngineOrder {
        bytes32 orderId;
        address[] assignedFeeders;
        uint256 rewardAmount;       // FEED 奖励
        bool settled;
    }

    /// @notice 外部协议喂价请求记录
    struct FeedRequest {
        address requester;          // 请求方合约/地址
        uint256 requiredFeeders;    // 所需喂价员数量
        uint256 rewardAmount;       // FEED 奖励
        uint256 timestamp;          // 请求时间
        bool exists;                // 是否存在
    }

    // ============ 子合约引用 ============

    /// @notice FEED 代币
    IERC20 public feedToken;

    /// @notice 共识引擎
    FeedConsensus public consensus;

    /// @notice 奖惩系统
    RewardPenalty public rewardPenalty;

    /// @notice NFT 执照
    FeederLicense public feederLicense;

    // ============ 状态变量 ============

    /// @notice 喂价员信息
    mapping(address => FeederInfo) public feeders;

    /// @notice 内部订单记录
    mapping(bytes32 => EngineOrder) public engineOrders;

    /// @notice 外部协议喂价请求
    mapping(bytes32 => FeedRequest) public feedRequests;

    /// @notice 已授权的协议合约（白名单）
    mapping(address => bool) public authorizedProtocols;

    /// @notice 各等级最低质押要求 (USDT, 18 decimals)
    mapping(FeederRank => uint256) public minStakeByRank;

    /// @notice 各等级每日最大抢单数
    mapping(FeederRank => uint256) public maxDailyGrabByRank;

    /// @notice 解锁等待期（秒）
    uint256 public unstakeCooldown;

    /// @notice 各等级升级所需 XP
    mapping(FeederRank => uint256) public xpThresholds;

    /// @notice 注册喂价员总数
    uint256 public totalFeeders;

    // ============ 事件 ============

    event FeederRegistered(address indexed feeder, uint256 licenseTokenId);
    event FeederRankUpdated(address indexed feeder, FeederRank oldRank, FeederRank newRank);
    event Staked(address indexed feeder, uint256 amount);
    event UnstakeRequested(address indexed feeder, uint256 amount);
    event Withdrawn(address indexed feeder, uint256 amount);
    event OrderGrabbed(bytes32 indexed orderId, address indexed feeder);
    event OrderSettled(bytes32 indexed orderId, uint256 consensusPrice, uint256 reward);
    event XPAwarded(address indexed feeder, uint256 amount, string reason);
    event FeedRequested(bytes32 indexed orderId, address indexed requester, uint256 requiredFeeders, uint256 rewardAmount);
    event ProtocolAuthorized(address indexed protocol, bool authorized);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /**
     * @notice 初始化
     */
    function initialize(
        address owner_,
        address feedToken_,
        address consensus_,
        address rewardPenalty_,
        address feederLicense_
    ) public initializer {
        __Ownable_init(owner_);
        __UUPSUpgradeable_init();
        __ReentrancyGuard_init();

        feedToken = IERC20(feedToken_);
        consensus = FeedConsensus(consensus_);
        rewardPenalty = RewardPenalty(rewardPenalty_);
        feederLicense = FeederLicense(feederLicense_);

        unstakeCooldown = 7 days;

        // 默认最低质押 (18 decimals)
        minStakeByRank[FeederRank.F] = 100 * 1e18;
        minStakeByRank[FeederRank.E] = 200 * 1e18;
        minStakeByRank[FeederRank.D] = 500 * 1e18;
        minStakeByRank[FeederRank.C] = 1_000 * 1e18;
        minStakeByRank[FeederRank.B] = 2_500 * 1e18;
        minStakeByRank[FeederRank.A] = 5_000 * 1e18;
        minStakeByRank[FeederRank.S] = 25_000 * 1e18;

        // 每日最大抢单数
        maxDailyGrabByRank[FeederRank.F] = 10;
        maxDailyGrabByRank[FeederRank.E] = 15;
        maxDailyGrabByRank[FeederRank.D] = 20;
        maxDailyGrabByRank[FeederRank.C] = 30;
        maxDailyGrabByRank[FeederRank.B] = 50;
        maxDailyGrabByRank[FeederRank.A] = 100;
        maxDailyGrabByRank[FeederRank.S] = type(uint256).max; // 无限

        // XP 升级阈值
        xpThresholds[FeederRank.F] = 0;
        xpThresholds[FeederRank.E] = 1_000;
        xpThresholds[FeederRank.D] = 3_000;
        xpThresholds[FeederRank.C] = 8_000;
        xpThresholds[FeederRank.B] = 20_000;
        xpThresholds[FeederRank.A] = 50_000;
        xpThresholds[FeederRank.S] = 100_000;
    }

    // ============ 喂价员注册 ============

    /**
     * @notice 注册为喂价员
     * @dev 需先 approve FEED 代币用于质押
     * @param stakeAmount 初始质押金额
     */
    function registerFeeder(uint256 stakeAmount) external nonReentrant {
        require(!feeders[msg.sender].registered, "Already registered");
        require(stakeAmount >= minStakeByRank[FeederRank.F], "Insufficient stake");

        // 转入质押
        feedToken.transferFrom(msg.sender, address(this), stakeAmount);

        // 注册
        feeders[msg.sender] = FeederInfo({
            registered: true,
            rank: FeederRank.F,
            xp: 0,
            totalFeeds: 0,
            stakedAmount: stakeAmount,
            unstakeRequestTime: 0,
            dailyGrabCount: 0,
            lastGrabDate: 0
        });

        totalFeeders++;

        // 铸造基础执照 NFT
        uint256 tokenId = feederLicense.mint(
            msg.sender,
            "ipfs://QmDefault",
            FeederLicense.LicenseType.BASIC
        );

        emit FeederRegistered(msg.sender, tokenId);
    }

    // ============ 质押管理 ============

    /**
     * @notice 追加质押
     */
    function stake(uint256 amount) external nonReentrant {
        require(feeders[msg.sender].registered, "Not registered");
        require(amount > 0, "Zero amount");

        feedToken.transferFrom(msg.sender, address(this), amount);
        feeders[msg.sender].stakedAmount += amount;

        emit Staked(msg.sender, amount);
    }

    /**
     * @notice 请求解除质押
     */
    function requestUnstake() external {
        FeederInfo storage feeder = feeders[msg.sender];
        require(feeder.registered, "Not registered");
        require(feeder.unstakeRequestTime == 0, "Already requested");

        feeder.unstakeRequestTime = block.timestamp;
        emit UnstakeRequested(msg.sender, feeder.stakedAmount);
    }

    /**
     * @notice 提取已解锁的质押
     */
    function withdraw() external nonReentrant {
        FeederInfo storage feeder = feeders[msg.sender];
        require(feeder.registered, "Not registered");
        require(feeder.unstakeRequestTime > 0, "No unstake request");
        require(
            block.timestamp >= feeder.unstakeRequestTime + unstakeCooldown,
            "Cooldown not met"
        );

        uint256 amount = feeder.stakedAmount;
        require(amount > 0, "Zero balance");

        feeder.stakedAmount = 0;
        feeder.unstakeRequestTime = 0;

        feedToken.transfer(msg.sender, amount);

        emit Withdrawn(msg.sender, amount);
    }

    // ============ 订单管理 ============

    /**
     * @notice 抢单
     * @param orderId 订单 ID
     */
    function grabOrder(bytes32 orderId) external {
        FeederInfo storage feeder = feeders[msg.sender];
        require(feeder.registered, "Not registered");
        require(feeder.stakedAmount >= minStakeByRank[feeder.rank], "Insufficient stake for rank");
        require(rewardPenalty.canGrabOrder(msg.sender), "Banned from grabbing");

        // 每日抢单数限制
        uint256 today = block.timestamp / 1 days;
        if (feeder.lastGrabDate != today) {
            feeder.dailyGrabCount = 0;
            feeder.lastGrabDate = today;
        }
        require(feeder.dailyGrabCount < maxDailyGrabByRank[feeder.rank], "Daily grab limit reached");

        // 记录
        engineOrders[orderId].assignedFeeders.push(msg.sender);
        feeder.dailyGrabCount++;

        emit OrderGrabbed(orderId, msg.sender);
    }

    /**
     * @notice 结算订单（由 operator/owner 调用）
     * @param orderId 订单 ID
     * @param rewardAmount 奖励总额
     */
    function settleOrder(bytes32 orderId, uint256 rewardAmount) external onlyOwner nonReentrant {
        EngineOrder storage eo = engineOrders[orderId];
        require(!eo.settled, "Already settled");
        require(eo.assignedFeeders.length > 0, "No feeders assigned");

        eo.settled = true;
        eo.rewardAmount = rewardAmount;

        // 获取共识价格
        uint256 cPrice = consensus.getConsensusPrice(orderId);

        // 结算共识合约中的订单
        consensus.settleOrder(orderId);

        // 分配奖励
        if (rewardAmount > 0) {
            rewardPenalty.distributeRewards(orderId, eo.assignedFeeders, rewardAmount);
        }

        // 给参与者加 XP
        for (uint256 i = 0; i < eo.assignedFeeders.length; i++) {
            _awardXP(eo.assignedFeeders[i], 50, "feed_completed");
        }

        emit OrderSettled(orderId, cPrice, rewardAmount);
    }

    // ============ 等级系统 ============

    /**
     * @notice 发放 XP 并检查升级
     */
    function _awardXP(address feederAddr, uint256 amount, string memory reason) internal {
        FeederInfo storage feeder = feeders[feederAddr];
        if (!feeder.registered) return;

        feeder.xp += amount;
        feeder.totalFeeds++;

        emit XPAwarded(feederAddr, amount, reason);

        // 检查升级
        _checkRankUp(feederAddr);
    }

    /**
     * @notice 检查并执行等级升级
     */
    function _checkRankUp(address feederAddr) internal {
        FeederInfo storage feeder = feeders[feederAddr];
        FeederRank currentRank = feeder.rank;

        // 逐级检查
        if (currentRank < FeederRank.S) {
            FeederRank nextRank = FeederRank(uint8(currentRank) + 1);
            if (
                feeder.xp >= xpThresholds[nextRank] &&
                feeder.stakedAmount >= minStakeByRank[nextRank]
            ) {
                feeder.rank = nextRank;
                emit FeederRankUpdated(feederAddr, currentRank, nextRank);

                // 递归检查是否可以跳级
                _checkRankUp(feederAddr);
            }
        }
    }

    /**
     * @notice 手动发放 XP（管理员用）
     */
    function awardXP(address feederAddr, uint256 amount, string calldata reason) external onlyOwner {
        _awardXP(feederAddr, amount, reason);
    }

    // ============ 管理函数 ============

    /**
     * @notice 更新最低质押要求
     */
    function updateMinStake(FeederRank rank, uint256 amount) external onlyOwner {
        minStakeByRank[rank] = amount;
    }

    /**
     * @notice 更新解锁等待期
     */
    function updateUnstakeCooldown(uint256 cooldown) external onlyOwner {
        require(cooldown >= 1 days, "Too short");
        unstakeCooldown = cooldown;
    }

    /**
     * @notice 更新子合约地址
     */
    function updateSubContracts(
        address consensus_,
        address rewardPenalty_,
        address feederLicense_
    ) external onlyOwner {
        if (consensus_ != address(0)) consensus = FeedConsensus(consensus_);
        if (rewardPenalty_ != address(0)) rewardPenalty = RewardPenalty(rewardPenalty_);
        if (feederLicense_ != address(0)) feederLicense = FeederLicense(feederLicense_);
    }

    // ============ 查询函数 ============

    /**
     * @notice 获取喂价员完整信息
     */
    function getFeederInfo(address feederAddr)
        external
        view
        returns (
            bool registered,
            FeederRank rank,
            uint256 xp,
            uint256 totalFeeds,
            uint256 stakedAmount,
            uint256 pendingRewards
        )
    {
        FeederInfo storage f = feeders[feederAddr];
        return (
            f.registered,
            f.rank,
            f.xp,
            f.totalFeeds,
            f.stakedAmount,
            rewardPenalty.pendingRewards(feederAddr)
        );
    }

    /**
     * @notice 获取订单已分配的喂价员
     */
    function getOrderFeeders(bytes32 orderId) external view returns (address[] memory) {
        return engineOrders[orderId].assignedFeeders;
    }

    // ============ 外部协议集成接口 ============

    /**
     * @notice 外部协议发起喂价请求（NST 等链上协议调用）
     * @dev 需先将 FEED 代币 approve 给本合约作为奖励
     * @param orderId 订单 ID（由调用方生成 keccak256 哈希）
     * @param requiredFeeders 所需喂价员数量
     * @param rewardAmount 奖励金额（FEED 代币，18 decimals）
     */
    function requestFeed(
        bytes32 orderId,
        uint256 requiredFeeders,
        uint256 rewardAmount
    ) external nonReentrant {
        require(authorizedProtocols[msg.sender] || msg.sender == owner(), "Not authorized protocol");
        require(!feedRequests[orderId].exists, "Request already exists");
        require(requiredFeeders >= 3, "Minimum 3 feeders");
        require(rewardAmount > 0, "Zero reward");

        // 转入奖励代币
        feedToken.transferFrom(msg.sender, address(this), rewardAmount);

        // 记录请求
        feedRequests[orderId] = FeedRequest({
            requester: msg.sender,
            requiredFeeders: requiredFeeders,
            rewardAmount: rewardAmount,
            timestamp: block.timestamp,
            exists: true
        });

        // 设置 engineOrder（复用现有抢单逻辑）
        engineOrders[orderId].orderId = orderId;
        engineOrders[orderId].rewardAmount = rewardAmount;

        emit FeedRequested(orderId, msg.sender, requiredFeeders, rewardAmount);
    }

    /**
     * @notice 获取共识价格（供外部协议查询）
     * @param orderId 订单 ID
     * @return price 共识价格
     * @return timestamp 共识时间戳
     * @return finalized 是否已完成结算
     */
    function getConsensusPrice(bytes32 orderId) external view returns (
        uint256 price,
        uint256 timestamp,
        bool finalized
    ) {
        price = consensus.getConsensusPrice(orderId);
        timestamp = feedRequests[orderId].timestamp;
        finalized = engineOrders[orderId].settled;
    }

    /**
     * @notice 授权/取消授权外部协议合约
     * @param protocol 协议合约地址
     * @param authorized 是否授权
     */
    function setAuthorizedProtocol(address protocol, bool authorized) external onlyOwner {
        require(protocol != address(0), "Zero address");
        authorizedProtocols[protocol] = authorized;
        emit ProtocolAuthorized(protocol, authorized);
    }

    /**
     * @notice 检查协议是否已授权
     */
    function isProtocolAuthorized(address protocol) external view returns (bool) {
        return authorizedProtocols[protocol];
    }

    function _authorizeUpgrade(address newImplementation) internal override onlyOwner {}
}

